package kotlinx.coroutines

import kotlin.test.*
import kotlin.time.*
import kotlin.time.Duration.Companion.milliseconds
import kotlin.time.Duration.Companion.nanoseconds

class DelayPrecisionTest : TestBase() {
    @Test
    fun testToDelayMillis() {
        assertEquals(0, 0.milliseconds.toDelayMillis())
        assertEquals(1, 1.nanoseconds.toDelayMillis())
        assertEquals(1, 999_999.nanoseconds.toDelayMillis())
        assertEquals(1, 1.milliseconds.toDelayMillis())
        assertEquals(2, (1.milliseconds + 1.nanoseconds).toDelayMillis())
        assertEquals(1000, (999.milliseconds + 1_000_000.nanoseconds).toDelayMillis())
        assertEquals(1000, (999.milliseconds + 999_999.nanoseconds).toDelayMillis())

        val expectedDuration = 998.milliseconds + 902752.nanoseconds
        assertEquals(999, expectedDuration.toDelayMillis())
    }

    @Test
    fun testDelayPrecision() = runTest {
        val expectedDuration = 998.milliseconds + 902752.nanoseconds
        // With the fix, delay(expectedDuration) should delay for 999ms
        // We use a fake delay to verify the value
        val context = coroutineContext
        val delayNode = object : Delay {
            var delayedTime = -1L
            override fun scheduleResumeAfterDelay(timeMillis: Long, continuation: CancellableContinuation<Unit>) {
                delayedTime = timeMillis
                continuation.resume(Unit)
            }
        }

        withContext(delayNode) {
            delay(expectedDuration)
        }
        assertEquals(999, delayNode.delayedTime)
    }
}
